logger = logging.getLogger(__name__)


def _sanitize_log_msg(msg: str) -> str:
    """Удаляет токены и чувствительные данные из логов."""
    if not msg:
        return msg
    import re

    # Telegram bot tokens
    msg = re.sub(r"\b\d{8,10}:[A-Za-z0-9_-]{35}\b", "[TOKEN]", msg)
    # API keys
    msg = re.sub(r"\b(gsk_|sk-|AIza)[A-Za-z0-9_-]{20,}\b", "[API_KEY]", msg)
    # Database URLs (маскируем пароль)
    msg = re.sub(r"(mysql|postgres)://[^:]+:[^@]+@", r"\1://user:***@", msg)
    return msg


_CACHE_MAX_AGE_HOURS = 48
_tls = threading.local()

_AD_SCHEMA_INIT_DONE = False
_AD_SCHEMA_INIT_LOCK = threading.Lock()
_PING_THROTTLE_SEC = 60


def _get_conn() -> Optional[pymysql.Connection]:
    return getattr(_tls, "conn", None)


def _set_conn(conn: Optional[pymysql.Connection]) -> None:
    _tls.conn = conn


def _get_last_ping() -> float:
    return getattr(_tls, "last_ping", 0.0)


def _set_last_ping(t: float) -> None:
    _tls.last_ping = t


def _parse_mysql_url(url: str) -> dict:
    u = urlparse(url)
    path = (u.path or "").strip("/")
    return {
        "host": u.hostname or "localhost",
        "port": int(u.port or 3306),
        "user": u.username or "root",
        "password": u.password or "",
        "database": path or "your_database",
        "charset": "utf8mb4",
    }


def _get_url() -> str:
    # Отдельный URL для антиделита
    return (os.getenv("AD_DATABASE_URL") or "").strip()


def _connect() -> pymysql.Connection:
    url = _get_url()
    if not url:
        raise RuntimeError("AD_DATABASE_URL not set")
    params = _parse_mysql_url(url)
    params["connect_timeout"] = 10
    conn = pymysql.connect(**params)
    _set_conn(conn)
    return conn


def _close_conn() -> None:
    conn = _get_conn()
    if conn:
        try:
            conn.close()
        except Exception:
            pass
        _set_conn(None)


_CONN_ERRORS = (
    pymysql.err.OperationalError,
    pymysql.err.InterfaceError,
    ValueError,
)


def _retry_on_conn_error(fn: Callable) -> Callable:
    """Повтор операции при ошибке соединения (Lost connection, read of closed file)."""

    @functools.wraps(fn)
    def wrapper(*args, **kwargs):
        for attempt in range(2):
            try:
                return fn(*args, **kwargs)
            except _CONN_ERRORS as e:
                if attempt == 0:
                    _close_conn()
                    logger.info("AD MySQL reconnect after: %s", _sanitize_log_msg(str(e)))
                    continue
                logger.warning("ad_db: %s", _sanitize_log_msg(str(e)))
                raise
        return None  # unreachable

    return wrapper


@contextmanager
def _conn_cursor(commit: bool = True):
    """Контекстный менеджер для курсора. commit=False для read-only."""
    import time as _time
    url = _get_url()
    if not url:
        raise RuntimeError("AD_DATABASE_URL not set")
    conn = _get_conn()
    if conn is None:
        _connect()
        conn = _get_conn()
    else:
        now = _time.time()
        if (now - _get_last_ping()) >= _PING_THROTTLE_SEC:
            try:
                conn.ping(reconnect=True)
                _set_last_ping(now)
            except Exception:
                _close_conn()
                _connect()
                conn = _get_conn()
                _set_last_ping(_time.time())
    cur = conn.cursor(pymysql.cursors.DictCursor)
    try:
        yield cur
        if commit:
            conn.commit()
    except Exception as e:
        if conn:
            try:
                conn.rollback()
            except Exception:
                pass
        if isinstance(e, _CONN_ERRORS):
            _close_conn()
        logger.warning("ad_db: %s", _sanitize_log_msg(str(e)))
        raise
    finally:
        cur.close()


@_retry_on_conn_error
def _init_schema():
    """Создание таблиц anti-delete. Совместимо со старой схемой без account_id."""
    with _conn_cursor() as cur:
        # Пользователи (телеграм-аккаунты), у которых работает антиделит
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS axs_ad_users (
                account_id BIGINT PRIMARY KEY,
                account_name VARCHAR(64),
                created_at DATETIME(6) DEFAULT CURRENT_TIMESTAMP(6),
                last_seen_at DATETIME(6) DEFAULT CURRENT_TIMESTAMP(6)
            )
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS axs_anti_delete_config (
                account_id BIGINT NOT NULL DEFAULT 0,
                chat_id BIGINT NOT NULL,
                is_on TINYINT(1) NOT NULL DEFAULT 1,
                PRIMARY KEY (account_id, chat_id)
            )
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS axs_message_cache (
                account_id BIGINT NOT NULL DEFAULT 0,
                chat_id BIGINT NOT NULL,
                msg_id INT NOT NULL,
                text TEXT,
                sender_id BIGINT,
                is_bot TINYINT(1) NOT NULL DEFAULT 0,
                created_at DATETIME(6) DEFAULT CURRENT_TIMESTAMP(6),
                PRIMARY KEY (account_id, chat_id, msg_id),
                INDEX (account_id, msg_id)
            )
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS axs_deleted_log (
                id BIGINT AUTO_INCREMENT PRIMARY KEY,
                account_id BIGINT NOT NULL DEFAULT 0,
                chat_id BIGINT NOT NULL,
                msg_id INT NOT NULL,
                text TEXT,
                sender_id BIGINT,
                deleted_at DATETIME(6) DEFAULT CURRENT_TIMESTAMP(6),
                INDEX (account_id, chat_id, deleted_at)
            )
            """
        )
        # Миграция: если старая схема без account_id, пересоздаём таблицы
        try:
            cur.execute("SELECT account_id FROM axs_anti_delete_config LIMIT 1")
        except Exception:
            for t in ("axs_deleted_log", "axs_message_cache", "axs_anti_delete_config"):
                try:
                    cur.execute(f"DROP TABLE IF EXISTS {t}")
                except Exception:
                    pass
            for stmt in (
                """
                CREATE TABLE IF NOT EXISTS axs_anti_delete_config (
                    account_id BIGINT NOT NULL DEFAULT 0,
                    chat_id BIGINT NOT NULL,
                    is_on TINYINT(1) NOT NULL DEFAULT 1,
                    PRIMARY KEY (account_id, chat_id)
                )
                """,
                """
                CREATE TABLE IF NOT EXISTS axs_message_cache (
                    account_id BIGINT NOT NULL DEFAULT 0,
                    chat_id BIGINT NOT NULL,
                    msg_id INT NOT NULL,
                    text TEXT,
                    sender_id BIGINT,
                    is_bot TINYINT(1) NOT NULL DEFAULT 0,
                    created_at DATETIME(6) DEFAULT CURRENT_TIMESTAMP(6),
                    PRIMARY KEY (account_id, chat_id, msg_id),
                    INDEX (account_id, msg_id)
                )
                """,
                """
                CREATE TABLE IF NOT EXISTS axs_deleted_log (
                    id BIGINT AUTO_INCREMENT PRIMARY KEY,
                    account_id BIGINT NOT NULL DEFAULT 0,
                    chat_id BIGINT NOT NULL,
                    msg_id INT NOT NULL,
                    text TEXT,
                    sender_id BIGINT,
                    deleted_at DATETIME(6) DEFAULT CURRENT_TIMESTAMP(6),
                    INDEX (account_id, chat_id, deleted_at)
                )
                """,
            ):
                try:
                    cur.execute(stmt)
                except Exception as e:
                    # 1050: table already exists
                    if getattr(e, "args", (None,))[0] != 1050:
                        raise

        # Миграция: добавляем флаг is_bot в кэш сообщений (если старые таблицы без колонки).
        try:
            cur.execute(
                "ALTER TABLE axs_message_cache ADD COLUMN is_bot TINYINT(1) NOT NULL DEFAULT 0"
            )
        except Exception:
            pass


def _ensure_init():
    global _AD_SCHEMA_INIT_DONE
    if _AD_SCHEMA_INIT_DONE:
        return
    with _AD_SCHEMA_INIT_LOCK:
        if _AD_SCHEMA_INIT_DONE:
            return
        try:
            _init_schema()
            _AD_SCHEMA_INIT_DONE = True
        except Exception as e:
            logger.exception("ad schema init: %s", e)
            raise


