    """Возвращает True, если антиделит включён для чата и аккаунта.

    По умолчанию (если записи нет) считаем, что антиделит ВКЛЮЧЁН.
    """
    _ensure_init()
    with _conn_cursor(commit=False) as cur:
        cur.execute(
            "SELECT is_on FROM axs_anti_delete_config WHERE account_id = %s AND chat_id = %s",
            (account_id, chat_id),
        )
        row = cur.fetchone()
        if row is None:
            return True
        return bool(row["is_on"])


