@_retry_on_conn_error
def anti_delete_cache_cleanup(max_age_hours: int = None) -> None:
    """Периодическая очистка старого кэша сообщений. Вызывать из фона раз в N минут."""
    _ensure_init()
    hours = max_age_hours if max_age_hours is not None else _CACHE_MAX_AGE_HOURS
    with _conn_cursor() as cur:
        cur.execute(
            """
            DELETE FROM axs_message_cache
            WHERE created_at < DATE_SUB(NOW(), INTERVAL %s HOUR)
            """,
            (hours,),
        )


@_retry_on_conn_error
def anti_delete_cache_find(
    chat_id: int,
    msg_id: int,
    account_id: int = 0,
) -> Optional[Tuple[int, str, Optional[int], int]]:
    """Находит кэшированное сообщение и возвращает (chat_id, text, sender_id, is_bot) или None."""
    _ensure_init()
    with _conn_cursor(commit=False) as cur:
        cur.execute(
            """
            SELECT chat_id, text, sender_id, is_bot
            FROM axs_message_cache
            WHERE account_id = %s AND chat_id = %s AND msg_id = %s
            """,
            (account_id, chat_id, msg_id),
        )
        row = cur.fetchone()
        if not row:
            return None
        return (
            row["chat_id"],
            (row["text"] or ""),
            row["sender_id"],
            int(row.get("is_bot") or 0),
        )


@_retry_on_conn_error
def anti_delete_cache_remove(chat_id: int, msg_id: int, account_id: int = 0) -> None:
    """Удаляет запись из кэша."""
