@_retry_on_conn_error
def anti_delete_log_list(
    chat_id: Optional[int] = None,
    limit: int = 30,
    account_id: int = 0,
) -> List[Tuple[int, int, str, Optional[int], Any]]:
    """Список последних удалённых сообщений.

    Возвращает список кортежей (chat_id, msg_id, text, sender_id, deleted_at).
    """
    _ensure_init()
    limit = max(1, min(200, int(limit or 30)))
    with _conn_cursor(commit=False) as cur:
        if chat_id is not None:
            cur.execute(
                """
                SELECT chat_id, msg_id, text, sender_id, deleted_at
                FROM axs_deleted_log
                WHERE account_id = %s AND chat_id = %s
                ORDER BY deleted_at DESC LIMIT %s
                """,
                (account_id, chat_id, limit),
            )
        else:
            cur.execute(
                """
                SELECT chat_id, msg_id, text, sender_id, deleted_at
                FROM axs_deleted_log
                WHERE account_id = %s
                ORDER BY deleted_at DESC LIMIT %s
                """,
                (account_id, limit),
            )
        return [
            (
                r["chat_id"],
                r["msg_id"],
                r["text"] or "",
                r["sender_id"],
                r["deleted_at"],
            )
            for r in cur.fetchall()
        ]

